  const sizeShifted = sub(sizeMul5, 5);
  const xsize = exp(sizeShifted);
  const blur2 = mul(blur, blur);
  const xblur = mul(blur2, blur2);
  const lo = sub(xsize, xblur);
  const hi = add(xsize, xblur);
  const k = smoothstep(lo, hi, dist);

